func kindDescription(obj client.Object) string {
	if isNil(obj) {
		return "unknown type"
	}
	if gvk := obj.GetObjectKind().GroupVersionKind(); !gvk.Empty() {
		return gvk.String()
	}
	return fmt.Sprintf("%T", obj)
}

