package main

import (
    "fmt"
    "os"
    "strings"

    corev1 "k8s.io/api/core/v1"
    metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
    "k8s.io/apimachinery/pkg/apis/meta/v1/unstructured"
    "k8s.io/apimachinery/pkg/runtime/schema"

    "sigs.k8s.io/controller-runtime/pkg/handler"
    "sigs.k8s.io/controller-runtime/pkg/reconcile"
    "sigs.k8s.io/controller-runtime/pkg/source"
)

func metadata(gvk schema.GroupVersionKind) *metav1.PartialObjectMetadata {
    obj := &metav1.PartialObjectMetadata{}
    obj.SetGroupVersionKind(gvk)
    return obj
}

func dynamic(gvk schema.GroupVersionKind) *unstructured.Unstructured {
    obj := &unstructured.Unstructured{}
    obj.SetGroupVersionKind(gvk)
    return obj
}

func check(name string, description string, want string, forbidden string) bool {
    fmt.Printf("%s: %s\n", name, description)
    if !strings.Contains(description, want) {
        fmt.Fprintf(os.Stderr, "%s: expected %q to contain %q\n", name, description, want)
        return false
    }
    if forbidden != "" && strings.Contains(description, forbidden) {
        fmt.Fprintf(os.Stderr, "%s: expected %q not to contain %q\n", name, description, forbidden)
        return false
    }
    return true
}

func main() {
    ok := true
    podMeta := source.TypedKind(nil, metadata(schema.GroupVersionKind{Version: "v1", Kind: "Pod"}), handler.TypedFuncs[*metav1.PartialObjectMetadata, reconcile.Request]{})
    ok = check("metadata pod", fmt.Sprintf("%s", podMeta), "/v1, Kind=Pod", "*v1.PartialObjectMetadata") && ok

    crMeta := source.TypedKind(nil, metadata(schema.GroupVersionKind{Group: "cert-manager.io", Version: "v1", Kind: "CertificateRequest"}), handler.TypedFuncs[*metav1.PartialObjectMetadata, reconcile.Request]{})
    ok = check("metadata crd", fmt.Sprintf("%s", crMeta), "cert-manager.io/v1, Kind=CertificateRequest", "*v1.PartialObjectMetadata") && ok

    missingGVKMeta := source.TypedKind(nil, &metav1.PartialObjectMetadata{}, handler.TypedFuncs[*metav1.PartialObjectMetadata, reconcile.Request]{})
    ok = check("metadata missing gvk", fmt.Sprintf("%s", missingGVKMeta), "*v1.PartialObjectMetadata", "") && ok

    pod := source.TypedKind(nil, &corev1.Pod{}, handler.TypedFuncs[*corev1.Pod, reconcile.Request]{})
    ok = check("structured pod", fmt.Sprintf("%s", pod), "*v1.Pod", "") && ok

    deploy := source.TypedKind(nil, dynamic(schema.GroupVersionKind{Group: "apps", Version: "v1", Kind: "Deployment"}), handler.TypedFuncs[*unstructured.Unstructured, reconcile.Request]{})
    ok = check("unstructured deployment", fmt.Sprintf("%s", deploy), "apps/v1, Kind=Deployment", "*unstructured.Unstructured") && ok

    if !ok {
        os.Exit(1)
    }
}
EOF
