    "k8s.io/apimachinery/pkg/api/meta"
    metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
    "k8s.io/apimachinery/pkg/runtime"
    "k8s.io/apimachinery/pkg/runtime/schema"
    "k8s.io/client-go/rest"

    cacheinternal "sigs.k8s.io/controller-runtime/pkg/cache/internal"
)

func main() {
    gvk := schema.GroupVersionKind{Version: "v1", Kind: "Pod"}
    mapper := meta.NewDefaultRESTMapper([]schema.GroupVersion{gvk.GroupVersion()})
    resource := schema.GroupVersionResource{Version: "v1", Resource: "pods"}
    mapper.AddSpecific(gvk, resource, resource, meta.RESTScopeNamespace)

    informers := cacheinternal.NewInformers(&rest.Config{Host: "http://127.0.0.1"}, &cacheinternal.InformersOpts{
        Scheme:               runtime.NewScheme(),
        Mapper:               mapper,
        EnableWatchBookmarks: true,
    })

    obj := &metav1.PartialObjectMetadata{}
    obj.SetGroupVersionKind(gvk)
    block := false
    _, entry, err := informers.Get(context.Background(), gvk, obj, false, &cacheinternal.GetOptions{BlockUntilSynced: &block})
    if err != nil {
        fmt.Fprintln(os.Stderr, err)
        os.Exit(1)
    }

    description := reflect.ValueOf(entry.Informer).Elem().FieldByName("objectDescription").String()
    fmt.Println(description)
    if description != "/v1, Kind=Pod" {
        fmt.Fprintf(os.Stderr, "unexpected objectDescription %q\n", description)
        os.Exit(1)
    }
}
EOF
